%Use some example data in Matlab
load carsmall
%One of the features is weight - build a Gaussian model of p(x) using MLE!
m1 = mean(Weight);
s1 = std(Weight);
clf;
%Plot the data in black
plot(Weight,zeros(100,1),'k*');
hold on;
xp = 0:60:6000;
plot(xp,normpdf(xp,m1,s1),'b');
xlabel('Weight');
ylabel('p(Weight)');

figure;
%Plot the data in black
plot(Weight,zeros(100,1),'k*');
hold on;
%Use our generative model to generate new data from p(x)
for i=1:10
    w1 = m1 + s1*randn(100,1);
    plot(w1,i*ones(100,1),'*');
    xlabel('Weight');
    ylabel('Sampling trial number (true data at 0)')
end

data2d = [Horsepower Acceleration];

% Find rows with NaN
rowsWithNaN = any(isnan(data2d), 2);  % Check row-wise (dimension 2)
% Remove rows with NaN
data2dclean = data2d(~rowsWithNaN, :);

mv = mean(data2dclean);
covv = cov(data2dclean);

% Create grid
x = linspace(min(Horsepower), max(Horsepower), 100);
y = linspace(min(Acceleration), max(Acceleration), 100);
[X, Y] = meshgrid(x, y);

% Compute PDF
Z = mvnpdf([X(:), Y(:)], mv, covv);
Z = reshape(Z, size(X));

% Plot
figure;
contourf(X, Y, Z, 'LineWidth', 1.5);
colorbar;
xlabel('X'); ylabel('Y');
title('2D Gaussian PDF Contours');
hold on;
plot(data2dclean(:,1),data2dclean(:,2),'w*');

x = rand(20,1);
y = cos(x);
y = y + 0.1*randn(20,1);
figure;
plot(x,y,'.')
p1 = polyfit(x,y,1)
x1 = linspace(0,1);
y1 = polyval(p1,x1);
hold on
plot(x1,y1)
xsqd = x.^2;
xcub = x.^3;
z = [x xsqd xcub];
%Doh! polyfit can only do regression with 1 input
b = ones(20,1);
z = [b z];
p3 = inv(z'*z)*z'*y;
p3
y3 = zeros(1,100);
for i=1:100
y3(i) = p3(1) + p3(2)*x1(i) + p3(3)*(x1(i).^2) + p3(4)*(x1(i).^3);
end
plot(x1,y3,'b');

clear *;
clf;
x = 5*rand(50,1);
y = x.^2;
y = y + 2*randn(50,1);
plot(x,y,'.')
n = 50;
lambda = 1;
l = 1;
d = pdist(x);
k = exp(-(d.^2)/(2*l^2));
K = squareform(k);
alpha = y'*inv(K + n*lambda*eye(50,50));
%Prediction
xtest = 0:0.1:5;
dtest = pdist2(x,xtest');
ktest = exp(-(dtest.^2)/(2*l^2));
ypred = alpha*ktest;
hold on;
plot(xtest,ypred,'k')

ddd = 0:0.1:5;
l = 0.5;
kddd = exp(-(ddd.^2)/(2*l^2));
figure;
plot(ddd,kddd);
hold on
l = 0.25;
kddd = exp(-(ddd.^2)/(2*l^2));
plot(ddd,kddd)

clf
%Specify the prior
alpha = 5;
beta = 10;
%Check it out via a sample of 500 points
xprior = betarnd(alpha,beta,500,1);
histogram(xprior)
hold on
%Specify a posterior
A1 = 20;
N1 = 30;
%Check it out via a sample of 500 points
xpost1 = betarnd(A1+alpha-1,N1-A1+beta-1,500,1);
histogram(xpost1)
%Specify a different posterior
A2 = 200;
N2 = 300;
%Check it out via a sample of 500 points
xpost2 = betarnd(A2+alpha-1,N2-A2+beta-1,500,1);
histogram(xpost2)

figure
x = linspace(-4,4,100);
y = normpdf(x);
plot(x,y,'.')
hold on
plot(x,y)
